INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Holiday Inn Express Bangkok Sathorn', 'holiday-inn-express-bangkok-sathorn-2', 'This is a day-use hotel in Bangkok. We offer convenient plans that can be used for early check-ins, layovers, and for one-day trips, packages, and tours.

Located in the middle of Sathorn’s Business district and Silom entertainment hub.
Suitable for both business and leisure travelers to explore all the dining and entertainment nearby venture out to Icon Siam.
Duty Free King Power Mahanakhon and Asiatique by the riverfront and catch a glimpse of the scenic Chao Phraya River.

★Great accessibility near the station
It''s located just a 3-minute walk from the BTS (Bangkok Skytrain) Chong Nonsi station, and parking is also available.

★Cafe
We have ''THE COFFEE CLUB - Holiday Inn Sathon'' located on the first floor.

★Meeting room
The hotel is equipped with a meeting room, which is readily available for use in business scenarios.

★Cleanliness
We ensure rigorous housekeeping so that our guests can spend their time comfortably and with peace of mind.', 'Bang Rak', 'thailand', '51 Soi Pipat, Silom, Bang Rak, Bangkok', 13.723939407536598, 100.53059935569763, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Fax", "Parking on Premises", "Gym", "Air Conditioner (Heating)", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', 'Hotel', 'In case of a same-day cancellation, 100% of the usage fee will be charged as a cancellation fee. Cancellations made up to the day before use will not incur any cancellation fees.\r\n\r\n*The cancellation policy is applied based on local time.', '2023-07-03 15:19:54', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Yellow Ribbon Hills Boutique Suites', 'yellow-ribbon-hills-boutique-suites', 'A 5-minute walk from Chong Nonsi BTS Skytrain Station, Yellow Ribbon Hills Boutique Suites offers comfortable accommodations with free WiFi. It features a fitness center, massage treatments and free parking.

Spacious suites at Yellow Ribbon Hills Boutique Suites feature an private bathroom with bathtub and amenities. They are well-equipped with satellite TV, in-room safe and a refrigerator.

A 24-hour front desk and tour desk with ticket service attends to guests’ needs. Yellow Ribbon Hills offers airport shuttle, car rental and laundry services. Free internet use is available at the lobby. The hotel also has a 24-hour convenience store.

Guests can dine at the hotel’s restaurant and coffee shop, which offer Thai, Italian and Japanese dishes. Buffet breakfast is served.

Yellow Ribbon Hills Boutique Suites is a 15-minute walk from Lumpini Park and Suanlum Night Bazaar. Suvarnabhumi International Airport is a 40-minute drive from the hotel.', 'Sathon', 'Thailand', '33 3 Naradhiwas Rajanagarindra 7 Alley, Thung Maha Mek, Sathon, Bangkok 10120', 13.7200778, 100.5325339, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Elevator in Building", "Parking on Premises", "Gym", "Air Conditioner (Heating)", "Kitchen", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', 'Hotel', 'Free Cancellation', '2023-07-13 16:57:03', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('The Landmark Bangkok', 'the-landmark-bangkok', 'With the Nana BTS Skytrain Station at its doorstep, The Landmark offers accommodations with Bangkok City views. It features 9 dining options and a 4-story shopping arcade. Free WiFi is available in public areas.

Located along Sukhumvit Road, The Landmark Bangkok is a 30-minute drive from Suvarnabhumi International Airport and less than 1.2 mi from Queen Sirikit National Convention Center.

Equipped with internet access, modern air-conditioned rooms at Landmark Bangkok feature large windows and a TV with satellite channels. A mini-bar and a safety deposit box are included, along with 24-hour room service.

A wide array of dining options can be found at Landmark including Rib Room &amp; Bar Steakhouse that serves gourmet steaks and French cuisines with an outstanding wine list. Asian delights can be found at Sui Sian and other international cuisines at Atrium. Refreshments and quick meals can be enjoyed at the 24-hour bistro Greenhouse and the Landmark Bakery &amp; Cafe. Guests can also sit back and relax with a refreshing drink at Rendezvous Bar and the Huntsman Pub.

Guests can exercise in the fitness center, swim in the outdoor pool or play a game of squash. The Landmark Bangkok’s business center opens 06:00-24:00 hrs.', 'Sukhumvit', 'Thailand', '138 Sukhumvit Road,Bangkok 10110, Thailand', 13.7412178, 100.5537884, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Parking on Premises", "Gym", "Pool", "TV", "Free Wi-Fi"]', 'Hotel', 'Free Cancellation up to 1 day prior to arrival date.', '2023-07-26 23:41:14', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Holiday Inn Express Bangkok Soi Soonvijai', 'holiday-inn-express-bangkok-soi-soonvijai', 'Discover the epitome of convenience at Holiday Inn Express Bangkok Soi Soonvijai, situated strategically amidst Bangkok''s premier medical facilities and vibrant shopping havens, our hotel offers an unparalleled stay. Just a quick 2-minute walk from Bangkok Hospital and Bangkok Plaza, and within a 10-minute drive from Phra Ram 9 Hospital and Piyavate Hospital, our location is ideal for health-focused tourists and business travelers. Additionally, we are a mere 14-minute drive from CentralPlaza Grand Rama 9, with easy access to the lively nightlife of Thong Lor and Ekkamai areas for those looking to unwind after a productive day.

Recharge yourself in a well-designed and comfortable room for your Bangkok trip. All guest rooms feature a high quality bed with your choice of soft or firm pillows. Enjoy convenient amenities like a tea &amp; coffee maker, in-room safe, refrigerator, 32-inch LCD TV, and ergonomic workstation. Refresh with multi-functional power shower and stay connected with free Wi-Fi as Holiday Inn Express signature.', 'Bangkok', 'Thailand', '19 Soi Soonvijai, New Petchburi Road, Huai Khwang', 13.74788133904, 100.58467537165, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Parking on Premises", "Gym", "Air Conditioner (Heating)", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', 'Hotel', 'Free Cancellation', '2023-08-21 10:31:06', 1);
