INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('The Cottage Suvarnabhumi / Superior Double or Twin Room – Roundtrip Airport Transfer', 'the-cottage-suvarnabhumi-superior-double-or-twin-room-roundtrip-airport-transfer', 'The Cottage Suvarnabhumi is a 15-minute drive from Suvarnabhumi Airport. Among the facilities of this property are a restaurant, a 24-hour front desk, and room service, along with free WiFi throughout the property.

Featuring a private balcony and an attached bathroom, each room at The Cottage has a flat-screen TV with satellite channels and a mini fridge. Some rooms enjoy direct access to the pool.

Luggage storage is provided at the 24-hour front desk. The hotel also has a business center and a terrace.

The Amigos Restaurant serves Thai and European cuisines. Diners can enjoy their meals indoors or on the terrace.

The Cottage Suvarnabhumi is within walking distance of Robinson Lifestyle and The Paseo Community Mall, which has restaurants, shops and banks. The property is 10-minute drive from Airport Link Lat Krabang Station. An airport shuttle service is available with an additional charge.', 'Lat Krabang', 'Thailand', '888/8 Lat Krabang Soi 20/2, Lat Krabang Road, Bangkok, 10520, Thailand', 13.72108361731, 100.72415828705, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Fax", "Parking on Premises", "Air Conditioner (Heating)", "Pool", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', 'Hotel', 'The guest can cancel free of charge until 1 day before arrival. The guest will be charged the first night''s cost if they cancel within 1 day before arrival. If the guest doesn''t show up, they will be charged the total price of the reservation.', '2023-09-28 19:25:25', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Hotel Mayank Residency / Deluxe Double Room – Free Airport Drop', 'hotel-mayank-residency-deluxe-double-room-free-airport-drop', 'Operating a 24-hour front desk, Airport Hotel Mayank Residency is only a 5-minute drive from Indira Gandhi International Airport and a convenient 8-minute drive to Ambience Mall. Free WiFi is available in the entire hotel, while complimentary private parking is provided.

Furnished with a desk and seating area, air-conditioned rooms are equipped with a personal safe, a flat-screen satellite TV and a mini fridge. En suite bathrooms come with a hairdryer, hot/cold shower facilities and free toiletries.

Airport Hotel Mayank Residency provides luggage storage, currency exchange and laundry services. A tour desk and a business centre are also available. Guests can rent a car to explore the area; alternatively, shuttle services can be arranged at extra charges.', 'New Delhi', 'india', 'A-230, Road no. 2, Mahipalpur Extension, 110037 New Delhi, India', 28.547699590633, 77.127013094723, '["Air Conditioner (Cooling)", "Fax", "Parking on Premises", "Air Conditioner (Heating)", "Scanner / Printer", "TV", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-10-13 10:32:27', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Dash Living on Prat / Superior Double or Twin Room', 'dash-living-on-prat-superior-double-or-twin-room', 'More than a Hip and Chic boutique experience, Dash Living on Prat invites indulgence in Tsim Sha Tsui''s vibrant excitements of shop &amp; dine. Within 10 minutes taxi ride to the Airport Express Kowloon Station easily reaching Hong Kong International Airport, the property is only 4 minutes walk to Tsim Sha Tsui MTR subway station. Through direct public transport nearby, popular attractions including Ocean Park and Mong Kok’s Ladies’ Market are conveniently connected.

Shopping can be endless – from Nathan Road to Canton Road – all is within walking distance. Hit the Avenue of Stars fronting Victoria Harbor; hang around for the nightly multimedia show named A Symphony of Lights.
The lifestyle-serviced apartment features spacious guest rooms for modern comfort.', 'Yau Tsim Mong District', 'Hong Kong', '21 Prat Avenue, Yau Tsim Mong District, Hong Kong, Hong Kong', 22.298469, 114.174928, '["Air Conditioner (Cooling)", "Elevator in Building", "Air Conditioner (Heating)", "TV", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-10-16 19:57:03', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Ago Hotel Chinatown / Superior Queen Room', 'ago-hotel-chinatown-superior-queen-room', 'A compact space for two for day used stay. This roomy space of 15 m² opens to a view of local shrine and lifestyle where the traditional touch of Talat Noi community is within your grasp. Take advantage of a full rest in the queen-sized bed and high-quality linens.

Ago Hotel Chinatown offers complimentary private parking, a communal lounge, and an on-site restaurant, along with free WiFi, room service, and a 24-hour front desk.

The rooms are equipped with air conditioning and feature amenities such as a desk, an electric kettle, a refrigerator, a safety deposit box, a smart TV equipped with YouTube and Netflix applications, and a private bathroom.

Guests can start their day with a choice of Continental or Asian breakfast options served each morning at the property.', 'Bangkok', 'Thailand', '177/20-25 Soi Choduek, Mahapruttharam Road Sampanthawong, Bangkok 10100, 10100 Bangkok, Thailand', 13.734570145829, 100.51556825638, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Parking on Premises", "TV", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is applied at the time of your reservation. Cancellation 3 day prior to arrival date no fee collection.  The cancellation less than 3 days, the charge will be 100% of the fee as a cancellation charge.  Non-refundable under any circumstances for less than 3 days cancellation.', '2023-10-25 14:04:57', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Column Bangkok Hotel / Studio Executive (Twin or King Bed)', 'column-bangkok-hotel-studio-executive-twin-or-king-bed', 'Overlooking Benjakitti Park, Column Bangkok Hotel offers accommodations with a kitchen and private balcony featuring views of Bangkok’s city skyline. This hotel houses an infinity pool as well as a fitness center on 25th Floor. Located on Sukhumvit 16, Terminal 21 shopping mall is only a 10-minute walk from the property.

Fitted with polished wooden floors, spacious contemporary studios and suites feature a living area and free WiFi. They are equipped with LCD TV, Kitchens include a stove, microwave and fridge.

Located next to 24-hour Foodland supermarket, Column Bangkok is 1640 feet from Asok BTS Skytrain Station and Sukhumvit MRT Subway Station. The famous Queen Sirikit National Convention Center is a 15 minute walk away.

Guests may exercise in the gym and swimming pool on the 25th floor with panoramic view. Other facilities include a business center. Parking is free.', 'Bangkok', 'thailand', '48 Sukhumvit Soi 16, Klongtoey, Khlong Toei, 10110 Bangkok, Thailand', 13.732918244103, 100.56090965867, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Parking on Premises", "Gym", "Air Conditioner (Heating)", "Kitchen", "Pool", "TV", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-10-26 16:07:05', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('カラム・バンコク・ホテル / スタジオ・エグゼクティブ（ツインまたはキングベッド）', '%e3%82%ab%e3%83%a9%e3%83%a0%e3%83%bb%e3%83%90%e3%83%b3%e3%82%b3%e3%82%af%e3%83%bb%e3%83%9b%e3%83%86%e3%83%ab-%e3%82%b9%e3%82%bf%e3%82%b8%e3%82%aa%e3%83%bb%e3%82%a8%e3%82%b0%e3%82%bc%e3%82%af', 'ベンジャキッティ公園を見渡すカラム・バンコク ホテルは、キッチンとバンコクの街並みを望む専用バルコニー付きの宿泊施設を提供しています。
このホテルにはインフィニティプールと25階のフィットネスセンターがあり、スクンビット16に位置し、ターミナル21ショッピングモールへは徒歩10分です。

広々とした現代的なスタジオとスイートには、リビングエリアと無料WiFiが備わっています。
キッチンにはコンロ、電子レンジ、冷蔵庫が完備されています。

カラム・バンコクは24時間営業のスーパーマーケット、フードランドの隣に位置し、BTSスカイトレインのアソーク駅と地下鉄MRTスクンビット駅から1640フィート（約500メートル）の距離にあります。
有名なクイーン・シリキット・ナショナル・コンベンション・センターまでは徒歩15分です。

パノラマビューの25階にあるジムとプールでエクササイズができ、その他の施設にはビジネスセンターがあります。
駐車場は無料でご利用いただけます。', 'Bangkok', 'thailand', '48 Sukhumvit Soi 16, Klongtoey, Khlong Toei, 10110 Bangkok, Thailand', 13.732918244103, 100.56090965867, '[]', NULL, 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-10-26 16:07:05', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Birdnest Guesthouse/Dormitory Room', 'birdnest-guesthouse-dormitory-room', 'Birdnest Guesthouse, Gaia Rooftop Cafe features a garden, terrace, a restaurant and bar in Kuala Lumpur. The property is around 1.9 miles from Kuala Lumpur Convention Center, 1.9 miles from Bank Negara Malaysia Museum and Art Gallery and 1.9 miles from Suria KLCC. The property provides a shared kitchen, an ATM and luggage storage for guests.

With a private bathroom equipped with a shower, rooms at the hostel also offer free WiFi, while selected rooms come with a city view. At Birdnest Guesthouse, Gaia Rooftop Cafe each room has bed linen and towels.

You can play darts at the accommodation.

Popular points of interest near Birdnest Guesthouse, Gaia Rooftop Cafe include KL Sentral, Berjaya Times Square and Islamic Arts Museum Malaysia. The nearest airport is Sultan Abdul Aziz Shah Airport, 14 miles from the hostel.', 'Kuala Lumpur', 'Malaysia', '210, Jalan Tun Hs Lee, 50000 Kuala Lumpur, Malaysia', 3.142712, 101.6966666, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Kitchen", "Wheelchair Accessible", "Free Wi-Fi"]', NULL, 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-10-31 21:09:05', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Floating Leaf Eco-Luxury Retreat/Single/Double Room', 'floating-leaf-eco-luxury-retreat-single-double-room', 'With a stay at Floating Leaf Eco-Luxury Retreat in Sukawati, you''ll be near the beach, within a 15-minute drive of Ubud Monkey Forest and Sukawati Market. This 4-star hotel is 7.8 mi (12.6 km) from Sanur Beach and 15.3 mi (24.6 km) from Kuta Beach.

Pamper yourself with a visit to the spa, which offers massages. You''re sure to appreciate the recreational amenities, including an outdoor pool and a fitness center. Additional amenities at this hotel include concierge services and barbecue grills. Guests can catch a ride to nearby destinations on the area shuttle (surcharge).

Satisfy your appetite for lunch or dinner at the hotel''s restaurant, or stay in and take advantage of the room service (during limited hours). Relax with your favorite drink at the bar/lounge or the poolside bar. A complimentary cooked-to-order breakfast is served daily from 6 AM to 10 AM.

Featured amenities include dry cleaning/laundry services, a 24-hour front desk, and luggage storage. Guests may use a roundtrip airport shuttle for a surcharge, and free self parking is available onsite.

Make yourself at home in one of the 10 air-conditioned guestrooms. Rooms have private balconies or patios. Complimentary wireless Internet access is available to keep you connected. Conveniences include separate sitting areas and complimentary bottled water, and housekeeping is provided daily.', 'Bali', 'Indonesia', '80582, Bali, Sukawati, Jl Pantai Purnama 42', -8.6117137, 115.3051844, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Parking on Premises", "Pool", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-04 19:58:41', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Bondalem Beach Club / Double or Twin Room', 'bondalem-beach-club-double-room', '8 double rooms with 2 single or 1 extra-wide king-size bed located on the ground or on the first floor of the 11-bedroom beachfront compound. True beachfront.
Amenities: tea/coffee/electric kettle, shower, safety deposit box, TV with satellite channels, Air conditioning, hairdryer, bathrobe and slippers, free toiletries, dressing room, drying rack for clothes.
Bondalem Beach Club is located in a traditional Bali village. Right on the seafront with colorful coral reef alongside a shoreline. The best of Bali waterfalls located nearby.', 'Bali', 'afghanistan', 'jalan Arcana, kelod Kangin, desa Bondalem, kecamatan Tejakula', -8.110425980883, 115.31916260719, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Parking on Premises", "Gym", "Pool", "TV", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-06 20:54:30', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('S31 Sukhumvit Hotel', 's31-sukhumvit-hotel-premier-double-room-2', 'Towering over trendy Sukhumvit, the iconic S31 offers modern 5-star accommodations with iPod docks and internet access. Located on the corner of Sukhumvit 31, it is a 5-minute walk from the Asoke and Phrom Phong BTS Stations.

A 5-minute walk from Emporium Shopping Mall, S31 Sukhumvit Hotel is conveniently located about 1 mi from Queen Sirikit National Convention Center. It is a 30-minute drive from Suvarnabhumi International Airport.

Featuring floor-to-ceiling windows, spacious rooms at S31 Sukhumvit feature modern dark wood furnishings, a double-door fridge and 32-inch flat-screen TV. Offering views of the bedroom, the luxurious bathrooms have a bathtub.

Enjoy refreshing workouts at the state-of-the-art fitness center, which comes with sauna and steam bath facilities. Other recreation options include a first-rate spa and an outdoor pool with city views.

Offering international dishes and panoramic city views, the rooftop restaurant is ideal for a fine dining experience. Light refreshments are available at the coffee shop throughout the day.', 'Bangkok', 'thailand', '545 Sukhumvit 31, Klongtoey-Nua, Wattana, Wattana, 10110 Bangkok, Thailand', 13.733642580993, 100.5658569932, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Fax", "Parking on Premises", "Gym", "Air Conditioner (Heating)", "Kitchen", "Pool", "TV", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-08 22:00:13', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('S15 Sukhumvit Hotel / Deluxe room', 's15-sukhumvit-hotel-deluxe-double-or-twin-room-2', 'In the central business district and shopping area on Sukhumvit 15, this hotel offers stylish accommodation for discerning business travelers and tourists.

Make the S15 Sukhumvit Hotel- SHA Plus Sukhumvit Hotel your meeting point in Bangkok. The hotel offers superb accommodation and gracious hospitality just a few steps from the Skytrain and subway stations.

At S15 Sukhumvit Hotel- SHA Plus Sukhumvit Hotel, your comfort is our priority. Refresh and rejuvenate yourself physically and mentally with treatments in the cozy spa rooms on 7th floor. Feeling wonderfully relaxed you can then retire to your stylish room furnished with Italian light fixtures, marble bath and separate rain shower.', 'Bangkok', 'thailand', '217 Sukhumvit 15, Klongtoey-Nua, Wattana, 10110 Bangkok, Thailand', 13.738953882221, 100.55837899446, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Fax", "Parking on Premises", "Gym", "Air Conditioner (Heating)", "TV", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-08 22:36:13', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('S33 Compact Sukhumvit Hotel / M – Deluxe room', 's33-compact-sukhumvit-hotel-standard-double-room-2', 'Located on Bangkok City’s Sukhumvit Road, S33 Compact Sukhumvit Hotel is a 5-minute walk from Prompong BTS Skytrain Station. It houses a coffee shop and stylish rooms with a flat-screen TV and free WiFi access.

S33 Compact Sukhumvit Hotel is a 10-minute drive from Queen Sirikrit Convention Center and a 45-minute drive from Suvarnabhumi International Airport.

Fitted with tiled flooring, the modern air-conditioned rooms at S33 Compact Sukhumvit Hotel are equipped with a personal safe. Private bathrooms come with bathrobes and slippers.

Members of staff at the 24-hour front desk can assist with airport shuttle, luggage storage and laundry services. Drivers can park on-site for free.', 'Bangkok', 'thailand', '9/7-17 Soi Sukhumvit 33 Sukhumvit Rd., Klongton-Nua Wattana, Wattana, 10110 Bangkok, Thailand', 13.734825486066, 100.56757092476, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Fax", "Parking on Premises", "TV"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-09 03:55:06', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('S Box Sukhumvit Hotel – SHA Extra Plus', 's-box-sukhumvit-hotel-sha-extra-plus-standard-double-room-2', 'Centrally located in Sukhumvit area, S Box Sukhumvit Hotel is 5 minutes walk from hotel to BTS-Phrom Phong and closed to shopping mall by walking distance. The hotel offer air-conditioned room with a safety deposit box and free WiFi.

Featuring a flat-screen satellite TV, each room also comes with a private bathroom fitted with a shower and free toiletries. Some units are equipped with an electric kettle and a refrigerator.

For guests’ convenience, the property provides a 24-hour front desk, luggage storage and laundry service. Guests can make use of airport shuttle at additional costs. There is a elevator available at this hotel.

Less than 800 meters from the hotel, guests will find BTS-Asok and MRT-Sukhumvit; while Korean Town is located 900 meters away. Suvarnabhumi Airport can be reached within 40 minutes by car.

Within 656 feet of the accommodations, a wide variety of local and international dining outlets are available. A complimentary mini-breakfast bar is provided for guests.', 'Bangkok', 'thailand', '4 Soi Sukhumvit 31, Klongtoey-Nua, Wattana, Wattana, 10110 Bangkok, Thailand', 13.733715535663, 100.56628346443, '["Air Conditioner (Cooling)", "Hair Dryer", "Elevator in Building", "Parking on Premises", "TV", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-09 04:07:38', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Bondalem Beach Club / Family Bungalow', 'bondalem-beach-club-family-bungalow', 'Double-storied Luxury Family Bungalow with a balcony on the second floor located only 15 meters from the sea and provide an astonishing sunrise view.
Each bungalow can comfortably accommodate 2 adults and 2 children.
An ideal variant for families with kids.
There is a king-size bed on the second floor with a balcony.
There are two sofa beds on the first floor that can be transformed into a king-size bed. Upon your request, we provide a baby cot for free.
Amenities: electric kettle, minibar, shower, safety deposit box, TV, Air conditioning, hairdryer, balcony, bathrobe and slippers, seating area, free toiletries, private entrance, mosquito net, wardrobe, sea view, garden view, pool view, drying rack for clothes.
Bondalem Beach Club is located in a traditional Bali village. Right on the seafront with colorful coral reef alongside a shoreline. The best of Bali waterfalls located nearby.', 'Bali', 'Indonesia', 'Bondalem Beach Club, jalan Arcana, desa Bondalem, kec.Tejakula, Bali, Indonesia', -8.1104180147383, 115.31916260719, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Gym", "Pool", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-09 15:47:00', 1);
