INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Holiday Inn Express – Yerevan by IHG', 'holiday-inn-express-yerevan-an-ihg-hotel-standard-room', 'Located within less than 0.6 mi of Republic Square in Yerevan, Holiday Inn Express - Yerevan has a number of amenities including a shared lounge. Armenian Opera and Ballet Theater is a 19-minute walk away from the property.

All rooms at the hotel are fitted with a seating area and a flat-screen TV with satellite channels. Holiday Inn Express - Yerevan offers certain units with city views, and rooms are equipped with an electric kettle and a mini-fridge. All guest rooms are carpeted and have a desk.

Air-conditioned units offer a private bathroom and free toiletries, slippers and hairdryer are included.

Breakfast is available each morning, and includes continental and buffet options. Guests can enjoy their meals at the À la Carte restaurant.

The accommodations also provides a business center and guests can check the newspapers at Holiday Inn Express - Yerevan. Staff speak English, French, Armenian and Russian at the reception.', 'Yerevan', 'Armenia', 'Buzand 97/2', 40.18324227876, 44.506677389145, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Fax", "Parking on Premises", "Air Conditioner (Heating)", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-09 21:38:30', 1);
