INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('LH – Easton Hotel', 'easton-hotel-standard-room', 'Not only located within easy reach of various places of interests for your adventure, but staying at Easton Kuta will also give you a pleasant stay.

Easton Kuta is highly recommended for backpackers who want to get an affordable stay yet comfortable at the same time.

For you, travelers who wish to travel comfortably on a budget, Easton Kuta is the perfect place to stay that provides decent facilities as well as great services.

Easton Kuta is a hotel near Airport, an ideal accommodation while waiting for your next flight. Enjoy a satisfying place to rest during your transit.

From business event to corporate gathering, Easton Kuta provides complete services and facilities that you and your colleagues need.

Have fun with various entertaining facilities for you and the whole family at Easton Kuta , a wonderful accommodation for your family holiday.

If you plan to have a long-term stay, staying at Easton Kuta is the right choice for you. Providing wide range of facilities and great service quality, this accommodation certainly makes you feel at home.

While traveling with friends can be a lot of fun, traveling solo has its own perks. As for the accommodation, Easton Kuta is suitable for you who value privacy during your stay.

WiFi is available within public areas of the property to help you to stay connected with family and friends.

Staying at Easton Kuta will surely satisfy you with its great hospitality and affordable price.', 'Bali', 'Indonesia', 'Gg. Nusa Indah No.3, Kuta, Kec. Kuta, Kabupaten Badung, Bali 80361 Indonesia', -8.7394043758706, 115.16770418463, '["Air Conditioner (Heating)", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-17 16:33:25', 1);
