INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Bagus Jati Health & Wellbeing Retreat / Superior Chalet', 'bagus-jati-health-wellbeing-retreat-superior-chalet-2', 'Located in hillside gardens and surrounded by tropical forests in Ubud, Bali, Bagus Jati Health &amp; Wellbeing Retreat offers spacious villas and a free shuttle service to Ubud''s town center twice daily. The property has its own waterfall, swimming pool and 2 yoga bales facing a tropical forest.

All villas at Bagus Jati Health &amp; Wellbeing Retreat feature views of the natural surroundings, a mini-bar, stereo and CD library. Deluxe Spa Villas have a private spa bath and spa treatment facilities.

Guests can enjoy free daily morning activities including yoga, nature walk, aqua aerobics Complimentary tea is served in the afternoons. Advanced requests must be made for detox treatments.

Indonesian cuisine is served at the Surya Restaurant &amp; Bar, which offers views of the river valley, gardens and Mount Agung.', 'Bali', 'Indonesia', 'Banjar Jati, Desa Sebatu, Kecamatan Tegallang, Bali, 80561 Tegalalang, Indonesia', -8.3659536206082, 115.30443938894, '["Bar / Restaurant", "Hair Dryer", "Fax", "Parking on Premises", "Gym", "Pool", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-24 23:32:28', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Bagus Agro Pelaga Resort / Superior Double or Twin Room', 'bagus-agro-pelaga-resort-superior-double-or-twin-room', 'Bagus Agro Pelaga is located in the Pucak Mangu Mountain Range, 3117 feet above sea level. It features 2 dining options, and villas with balconies and private plunge pools.

Located in Pelaga Village in Petang District, Pelaga Bagus Agro is an hour’s drive from Denpasar International Airport. Sangeh Village is a 30-minute drive away.

The two-bedroom villas come with a kitchenette and overlook Mount Agung. Private bathrooms in all villas come with amenities and both a bathtub and shower.

Guests can approach the tour desk at to help plan their itinerary. Currency exchange and car rental services are available. Agro Bagus Pelaga has a shop selling agricultural products.

Lotus Restaurant and Tunjung Restaurant serve both local and western cuisine.', 'Plaga', 'Indonesia', 'Jalan Raya Puncak Mangu, Desa Pelaga, Kecamatan Petang, 80353 Plaga, Indonesia', -8.2841032540919, 115.22568494081, '["Bar / Restaurant", "Hair Dryer", "Fax", "Parking on Premises", "Wheelchair Accessible", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-25 08:01:00', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Puri Bagus Candidasa / Deluxe Room with Garden View', 'puri-bagus-candidasa-deluxe-room-with-garden-view', 'Puri Bagus Candidasa offers villa accommodations with views of the resort’s gardens or beach. Its facilities include an outdoor swimming pool for dove training and 2 yoga venues facing a beautiful garden. Free WiFi is available throughout the resort.

Each villa at the Puri Bagus features a balcony and outdoor bathroom. Villa amenities include air conditioning, a flat-screen TV and mini-bar.

Guests can enjoy a private beachfront at the Puri Bagus Candidasa. Traditional Balinese massages and body treatments are available at the Jaya Spa. Enjoy yoga classes or attend a cooking class at the resort. A free shuttle service to the Candidasa area is provided.

Traditional Balinese and international cuisine is served at The Gringsing Restaurant &amp; Bar, which features views of the Indian Ocean. The pool’s bar serves light snacks.

Puri Bagus Candidasa is located 25 mi away from Ubud and is 56 mi away from Ngurah Rai Airport.', 'Candidasa', 'Indonesia', 'Jl. Raya Candidasa, Dusun Samuh, Desa Bugbug, Candidasa, Karangasem Bali Indonesia', -8.5137452770727, 115.57921886444, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Fax", "Parking on Premises", "Air Conditioner (Heating)", "Pool", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-25 10:02:25', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Puri Bagus Lovina Dive Resort & Yoga Retreat / Superior Room with Garden View', 'puri-bagus-lovina-resort-superior-room-with-garden-view', 'Puri Bagus Lovina offers spacious, Balinese and resort-style villas with balconies and views of the resort’s gardens and ocean. Its facilities include a beach facing infinity swimming pool and yoga bale. There is also an open-air restaurant and bar.

Villas at the Puri Bagus Lovina come with air conditioning, cable TV and a minibar. Each villa has a bathroom with indoor and outdoor shower.

Various massages, facial and body treatments are offered at the floating Jaya Spa, which is surrounded by a lotus pond. Free wireless internet access is available in the resort’s main areas. A private premium wooden boat is available for lunch and dinner check-in and pick-up, fresh water fishing and dolphin watching.

The resort features a breakfast and dinner cruise on a wooden boat. Saraswati Restaurant and Bar serves both international and Indonesian cuisines.', 'Lovina', 'Indonesia', 'Jl. Raya Seririt Singaraja, Desa Pemaron, Lovina, Singaraja, Bali Indonesia', -8.1282936461091, 115.06103754044, '["Bar / Restaurant", "Hair Dryer", "Fax", "Parking on Premises", "Pool", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-25 10:18:14', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Mode Sathorn Hotel / Deluxe Mode', 'mode-sathorn-hotel-deluxe-mode', 'Mode Sathorn Hotel - SHA Extra Plus is located across from Surasak BTS Skytrain station.
It offers stylish accommodations and free WiFi. Guests can indulge in spa treatments or stay active at the fitness center.

The property is a 15-minute drive from Silom Road. It is a 45-minute drive from Suvarnabhumi Airport.

Rooms at Mode Sathorn Hotel - SHA Extra Plus are furnished with contemporary decor.
Each room comes with a flat-screen satellite TV, a mini-bar and an electric kettle. Free toiletries and a hairdryer are included in an private bathroom. Bathrobes and slippers are also provided.

Guests can lounge by the pool.
The hotel is equipped with meeting rooms and a concierge service.
Staff at the 24-hour front desk can assist guests with currency exchange and luggage storage.

Breakfast can be sampled at The Sathorn. Guests. can enjoy drinks and views of the Chaopraya River at The Roof @38th Bar. Cocktails and wines are also offered at Pool Bar.', 'Bangkok', 'Thailand', '144, North Sathorn Road, Silom, Bangrak, Bangkok, 10500, Thailand', 13.719877191835, 100.52164614201, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Gym", "Air Conditioner (Heating)", "Pool", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-25 11:52:20', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('de Vins Sky Hotel Seminyak / Superior Terrace', 'de-vins-sky-hotel-seminyak-superior-terrace', 'Located on the hip and trendy Petitenget Street in Seminyak, de Vins Sky Hotel Seminyak offers an elegant and stylish stay with an outdoor swimming pool and free WiFi access throughout the entire property. Free on site private parking space is offered for guests who drive.

It only takes a 5-minute stroll from the property to the famous Potato Head Beach Club, and a 15-minute stroll to Petitenget Beach. Seminyak Square Shopping Centre is reachable within a 5-minute drive. Getting to Ngurah Rai International Airport will take 20 minutes by car.

The rooms at de Vins Sky Hotel Seminyak are all beautifully designed. Featuring a great combination of dark wood and warm colours, each room is air-conditioned and fitted with a seating area and many modern comforts like flat-screen cable TV. An en suite bathroom featuring bath or shower facility and free toiletries are also available in each room.

24-hour front desk with currency exchange, luggage storage and free shuttle service to Petitenget Beach and Seminyak Square are offered. While other facilities and services like business centre, meeting facility, sauna, spa and wellness centre, laundry, airport shuttle, and massage treatments are available with extra charges. Guests can also enjoy a free access to the fitness centre.

The reception at de Vins Sky Hotel Seminyak can provide tips on the area and assist with tour arrangements.

As for dining option, the on-site restaurant serves an array of delicious dishes with beautiful views. Guests can enjoy sunset views at BLUSky Restaurant-Bar-Lounge and from the rooftop pool.', 'Seminyak', 'indonesia', 'Jalan Petitenget, Komplex Villa Kendal No. 35, 80361 Seminyak, Indonesia', -8.6912894, 115.1681653, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Fax", "Parking on Premises", "Gym", "Pool", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-26 22:37:22', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Sanglung Villas & Suites / Premium Villa with Private Pool', 'sanglung-villas-villa-with-private-pool', 'Located in Kubutambahan, Sanglung Villas &amp; Suites Private Pool offers far-reaching views of the sea and lush greenery. It features a private infinity pool and semi open living space overlooking the tropical landscapes. Free WiFi is accessible in all areas.

Tastefully appointed with wooden flooring and high ceilings, the villa has a well-equipped kitchen and a dining area. All bedrooms have an private bathroom with bath or shower facilities. In-villa amenities include a safety deposit box, flat-screen satellite TV and DVD player.

Sanglung Villas &amp; Suites Private Pool is a 15-minute drive from Air Sanih Beach, 1-hour drive from Lovina Beach and a 2.5-hour drive from Ngurah Rai International Airport.

Room service is available.', 'Kubutambahan', 'Indonesia', 'Banjar Dinas Sangglung, Desa Depeha , 81113 Kubutambahan, Indonesia', -8.1020109, 115.2221361, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Gym", "Pool", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', NULL, 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-11-26 23:24:36', 1);
