INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Dash Living on Hollywood/ Deluxe Queen Bed', 'dash-living-on-hollywood-deluxe-queen-bed', 'These upscale hotel residences are located near Central’s Soho area, one of Hong Kong’s hippest nightlife districts (the other being Lan Kwai Fong, which is also close by). With suites that overlook Hong Kong’s mid-levels and central area, and only a five-minute walk from the nearest tram stop—one of Hong Kong’s oldest and most iconic forms of public transport—these hotel residences are perfect for anyone who wants to have fun without compromising convenience!', 'Hong Kong Island', 'Hong Kong', '263 Hollywood Road', 22.2856607, 114.1478972, '["Air Conditioner (Cooling)", "Hair Dryer", "TV", "Free Wi-Fi"]', 'Hotel', 'Non-cancellation and non-refundable', '2023-12-13 18:41:26', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Ago Hotel Chinatown / Superior Twin Room', 'ago-hotel-chinatown-superior-twin-room', 'Perfect for sharing with your travel buddy. This roomy space of 17 m² opens to a view of local shrine and lifestyle where the traditional touch of Talat Noi community is within your grasp. High quality amenities and comfy twin beds guarantee you a comfortable day used stay.

Ago Hotel Chinatown offers complimentary private parking, a communal lounge, and an on-site restaurant, along with free WiFi, room service, and a 24-hour front desk.

The rooms are equipped with air conditioning and feature amenities such as a desk, an electric kettle, a refrigerator, a safety deposit box, a smart TV equipped with YouTube and Netflix applications, and a private bathroom.

Guests can start their day with a choice of Continental or Asian breakfast options served each morning at the property.', 'Bangkok', 'Thailand', '177/21 Soi Choduek, Mahapruttharam Road Sampanthawong, Bangkok 10100, 10100 Bangkok, Thailand', 13.734570145829, 100.51556825638, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Parking on Premises", "TV", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is applied at the time of your reservation. Cancellation 3 day prior to arrival date no fee collection.  The cancellation less than 3 days, the charge will be 100% of the fee as a cancellation charge.  Non-refundable under any circumstances for less than 3 days cancellation.', '2023-12-13 18:56:11', 1);
