INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Saigon Domaine Luxury Residences / 1-Bedroom Suite', 'serviced-apartment-1-bedroom-1-queen-bed-sgn-airport-10km', 'Saigon Domaine Luxury Residences, an ideal choice for those who are looking for a peaceful, and relaxed atmosphere in a green environment with all comfort and luxury of a private home.

Domaine''s private residences are designed to achieve seamless balance between classic simplicity and contemporary luxury.

Situated in an island within the city, this first class Resort has received many international Awards. Peace, elegance and tradition guarantee an unforgettable stay.

This Oasis is ideal for jogging, cycling, fishing or simply lazing around on the riverbank.

Highlight the free boat ride to city center by day and night.', 'Ho Chi Minh City', 'vietnam', '1057 Binh Quoi street, Ward 28,  Binh Thanh district, Ho Chi Minh city, Vietnam', 10.823079040617, 106.73058986664, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Fax", "Parking on Premises", "Gym", "Air Conditioner (Heating)", "Kitchen", "Pool", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', NULL, 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-12-13 21:45:38', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Red Maple Bed &amp; Breakfast / Double / Twin Room', 'red-maple-bed-breakfast-double-twin-room', 'Red Maple Bed and Breakfast is in New Delhi, 4 miles from Connaught Place and the city center. The hotel features a dining room, free parking, and free Wi-Fi.

The modern rooms at Red Maple are air-conditioned, and come equipped with a 32-inch flat-screen TV. Each room has a safe, a minibar, and tea/coffee making facilities. Private bathrooms provide a hot shower.

The front desk is conveniently open 24 hours a day. The staff can help with car rental and laundry services.

Guests can order meals and enjoy them in the comfort of their rooms, or in the hotel’s dining room.

Red Maple Bed &amp; Breakfast is 9 miles from Indira Gandhi International Airport, and 6 miles from the domestic airport. Ansal Plaza shopping mall is one mile away.', 'New Delhi,', 'india', '49, Amrit Nagar, S.Ex- Part-I, 110003 New Delhi, India', 28.573538472353, 77.219636142254, '["Air Conditioner (Cooling)", "Hair Dryer", "Fax", "Parking on Premises", "Air Conditioner (Heating)", "TV", "Free Wi-Fi"]', NULL, 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-12-15 16:33:48', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Wedgewood Residences Mont Kiara / 1 Bedroom suite', 'wedgewood-residences-mont-kiara-1-bedroom-suite', 'Featuring an outdoor pool and a kids'' playground, Wedgewood Residences offers spacious and modern apartments. It is located 400 metres from SohoKL shopping centre. Free WiFi is accessible in all areas and free private parking is provided for guests who drive.

Each air-conditioned apartment includes a living area with a cable TV and a well-equipped kitchen. Some units have a dining area. The en suite bathroom is fitted with a bath, a shower and a hairdryer.

Guests enjoy daily buffet breakfast, served at the Garden Room. Other dining options are located within a 5-minute walk from the property.

Guests can relax by the pool or exercise in the fitness centre, while kids can play in the playground. The friendly staff at the 24/7 reception can help you with airport transfers and bicycle hires at an additional charge.

MATRADE Exhibition and Convention Centre is 1.6 km from Wedgewood Residences, while National Palace is 6.5 km from the property. The nearest airport is Sultan Abdul Aziz Shah Airport, 27 km drive away.

Additional services as below :
· Airport pick up / drop (additional cost and types of vehicle)
· Private shuttle to other destination and tour (additional cost)
· Extra bed (additional cost)
· Breakfast (additional cost)
· Meeting room (additional cost)
· AV charger for electric vehicle (additional cost)

Rates quoted include the following features and privileges
 Fully furnished suites with unsuited bathroom with bathtub &amp; shower.
 Private balcony.
 Free High-Speed WI-FI.
 Master Bedroom set-up with a King-sized bed complete with private bathroom.
 Bedroom 2 set-up with a Queen-sized bed with connecting bathroom.
 Bedroom 3 set-up with a Twin bed-single sized bed with connecting bathroom.
 In-room digital safe, hair dryer, iron and ironing board.
 Smart TV with Netflix in living area and LED TV in bedroom with
centralized cable channels.
 Suite with kitchenette (Fully Equipped Kitchen) with Coffee and Tea making
facilities.
 Washer and Dryer inside the suite.
 Daily cleaning or weekly cleaning.
 Free parking.

Wedgewood Residences Facilities:
 24 hours reception, concierge and Shuttle Services.
 Swimming pool &amp; Table Tennis.
 24 Gym, 24 CCTV and Security.
 Complimentary shuttle service (return) to International School as below :
 LFKL / France International School (primary &amp; secondary)
 MKIS / Mont Kiara International School
 GIS / Garden International School.', 'Kuala Lumpur', 'Afghanistan', 'La Grande Kiara ,Jalan Duta Kiara ,Bukit Kiara ,', 3.1745552253917, 101.65771722794, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Fax", "Parking on Premises", "Gym", "Pool", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', NULL, '・We allowed smoking only in smoking room (limited units)\r\n・We allowed pet (We have  limited pet friendly unit with fumigation cost (1 time charge)', '2023-12-15 18:00:36', 1);
