INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Yello Hotel / Superior Double Room', 'yello-hotel-superior-double-room', 'Located in Cebu City, 1.8 miles from Ayala Center Cebu, Yello Hotel provides accommodations with a restaurant, free private parking and a bar. Among the facilities at this property are room service and a 24-hour front desk, along with free WiFi throughout the property. The property has a concierge service and luggage storage space for guests.

Guest rooms in the hotel are equipped with a flat-screen TV with cable channels. All guest rooms at Yello Hotel feature air conditioning and a desk.

Buffet and continental breakfast options are available every morning at the accommodation.

There''s an on-site snack bar and guests can also use the business area.

SM City Cebu is 2.3 miles from Yello Hotel, while Fuente Osmena Circle is 2.3 miles away. The nearest airport is Mactan-Cebu International Airport, 7.5 miles from the hotel.', 'Cebu City', 'Philippines', '3 Wilson Place, Wilson Street, Lahug, Lahug, 6000 Cebu City, Philippines', 10.331506724727, 123.89964044094, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Elevator in Building", "Fax", "Parking on Premises", "Air Conditioner (Heating)", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2023-12-22 21:46:05', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Camp CJ / Studio unit rental in Mandaluyong, Philippines', 'camp-cj-entire-rental-unit-in-mandaluyong-philippines', 'Minimalist Boho inspired is what we aim to achieved for this place. CAMP CJ is a 20sqm. studio type condo unit, wherein every furnitures in this room are carefully chosen to give you a relaxing stay.

Rest easy in plush accommodations &amp; wake up to exciting adventures in the city, and/or spend quality time by playing board &amp; card games with your family or friends within our premises. Comfortability and affordability harmonize beautifully here for an unforgettable hotel-liked staycation escapade.

*The 20 USD listed as "City Fee" will be collected as a security deposit to be used for defacement, etc.
*We will refund it if there is no problem with the use of the room.
*Please let us know with your refund address via inbox.', 'Manila', 'Philippines', 'Sunshine 100 City Plaza Tower 3, Mandaluyong, Metro Manila, Philippines', 14.570199145669, 121.05165481567, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Parking on Premises", "Gym", "Kitchen", "Pool", "TV", "Free Wi-Fi"]', 'Private Room', '*Refundable cancellation is allowed at least 2 days before the day of use but not in full amount.\r\n*Non-refundable cancellation a day before and on the day of use', '2024-01-10 20:23:39', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Sanglung Villas &amp; Suites / Premium Villa with Private Pool &amp; See View', 'sanglung-villas-suites-premium-villa-with-private-pool-see-view', 'Located in Kubutambahan, Sanglung Villas &amp; Suites Private Pool offers far-reaching views of the sea and lush greenery. It features a private infinity pool and semi open living space overlooking the tropical landscapes. Free WiFi is accessible in all areas.

Tastefully appointed with wooden flooring and high ceilings, the villa has a well-equipped kitchen and a dining area. All bedrooms have an private bathroom with bath or shower facilities. In-villa amenities include a safety deposit box, flat-screen satellite TV and DVD player.

Sanglung Villas &amp; Suites Private Pool is a 15-minute drive from Air Sanih Beach, 1-hour drive from Lovina Beach and a 2.5-hour drive from Ngurah Rai International Airport.

Room service is available.', 'Kubutambahan', 'indonesia', 'Banjar Dinas Sangglung, Desa Depeha , 81113 Kubutambahan, Indonesia', -8.1020109, 115.2221361, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Gym", "Pool", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', NULL, 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2024-01-14 12:38:59', 1);
