INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('The Cottage Suvarnabhumi / Deluxe Room Roundtrip Airport Transfer', 'the-cottage-suvarnabhumi-deluxe-room-roundtrip-airport-transfer', 'The Cottage Suvarnabhumi is a 15-minute drive from Suvarnabhumi Airport. Among the facilities of this property are a restaurant, a 24-hour front desk, and room service, along with free WiFi throughout the property.

Featuring a private balcony and an attached bathroom, each room at The Cottage has a flat-screen TV with satellite channels and a mini fridge. Some rooms enjoy direct access to the pool.

Luggage storage is provided at the 24-hour front desk. The hotel also has a business center and a terrace.

The Amigos Restaurant serves Thai and European cuisines. Diners can enjoy their meals indoors or on the terrace.

The Cottage Suvarnabhumi is within walking distance of Robinson Lifestyle and The Paseo Community Mall, which has restaurants, shops and banks. The property is 10-minute drive from Airport Link Lat Krabang Station. An airport shuttle service is available with an additional charge.', 'Lat Krabang', 'Thailand', '888/8 Lat Krabang Soi 20/2, Lat Krabang Road, Bangkok, 10520, Thailand', 13.72108361731, 100.72415828705, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Elevator in Building", "Fax", "Parking on Premises", "Air Conditioner (Heating)", "Pool", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', 'Hotel', 'The guest can cancel free of charge until 1 day before arrival. The guest will be charged the first night''s cost if they cancel within 1 day before arrival. If the guest doesn''t show up, they will be charged the total price of the reservation.', '2024-01-30 13:48:07', 1);
