INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Spaces Hotel Makati / Standard Double Room', 'spaces-hotel-makati-standard-double-room-copy', 'A 10-minute walk from shops at the Greenbelt, Spaces Hotel Makati - People &amp; Pets offers affordable nonsmoking rooms with free WiFi. A daily breakfast is available at the on-site coffee shop. Luggage can be stored at the 24-hour front desk.

Simply furnished, all the air-conditioned guestrooms come with a flat-screen TV, an office desk and a telephone. The private bathroom is equipped with hot and cold shower facilities.

Spaces Hotel Makati - People &amp; Pets is a 10-minute drive from Makati Central Business District. Manila International Airport is 3.2 mi away. Airport pick-up and drop-off transfers can be arranged upon request at an extra cost.

Laundry services and in-room massage treatments can be made available at extra charges. There is also a business center and a tour desk.', 'Manila', 'philippines', 'Amorsolo Street cor V.A. Rufino Street Legaspi Village, Makati, Manila', 14.554871283599, 121.01444530368, '["Air Conditioner (Cooling)", "Bar / Restaurant", "Hair Dryer", "Parking on Premises", "Air Conditioner (Heating)", "TV", "Free Wi-Fi"]', 'Hotel', 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2024-02-29 19:26:57', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Isla Stays/Tambuli Seaside Resort and Spa', 'isla-stays-tambuli-seaside-resort-and-spa', '@TAMBULI, MARIBAGO, MACTAN. Experience the luxurious beach life in our spacious Tambuli Seaside Resort and Spa condo!
It is a modern style 37sqm studio unit that comes with a balcony that has a majestic view of nature.

The unit has the following (but not limited to) amenities:
(1) Kitchen (Complete equipments: Microwave, Rice Cooker, Stove, Hot Water, Utensils etc)
(2) WIFI
(3) LAUNDRY (Washing Machine)
(4) Alexa for Netflix, Youtube

GUESTS''ACCESS: Condo Lapping pool and kiddie pool is open from check in time till 6 pm daily.
For rents 2 weeks or more: FREE beach club amenities access depending on FIRST TO BOOK; FIRST TO AVAIL BASIS.
Only 3 names are allowed per unit per month.
This renews every first. Otherwise, we can arrange a per day use of pool amenities in the club.

For dining, beach hangout and gardens, you don’t need to arrange the ‘per day’ use.
DAY USE for beach club if booked with us will cost P800 per head with club towels included.
Alternatively, you may also purchase at the Resort Clubhouse lobby for P1500 weekdays and P1800 weekends and holidays.
This includes a P850 worth of dining credits.

FYI. Resort has the right to change rates so please check for any changes.
Important Note: Condo pool is closed on Wednesday for cleaning and maintenance.', 'Cebu', 'philippines', 'Buyong Rd, Maribago, Lapu-Lapu City, 6015 Cebu, Philippines', 10.289986346734, 124.00686979294, '["Hair Dryer"]', NULL, 'The cancellation policy outlined below is established by our website and is applied at the time of your reservation. If you cancel on the day of use, you will be charged 100% of the fee as a cancellation charge. If you cancel by the day before the date of use, no cancellation fee will be incurred. Please note that some facilities may not follow the cancellation policy of our site, but instead apply their own unique cancellation policy. Always check the cancellation policy listed on the information page of the facility you plan to use.', '2024-03-05 23:09:52', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Palmyra Residence Whole Condo / 2 Queen & 1 Single Beds', 'luxyry-home-with-reasonably-price-spend-time-with-family', 'Palmyra Residence Whole Condo offer a sauna and free private parking, and is within 23 km of District 21 IOI CITY and 24km of IOI CITYMALL. Among the facilities of this property are a restaurant, a lift and a 24 hour security, along with free Wi-Fi throughout the property. the apartment features a pool with a size of Olympic pool, scenery views, jacuzzi and private plus self check-in and check-out without people interaction.

The 3-bedroom apartment is fitted with a ling room with a Smart-TV flat screen with free Netflix service, a fully equipped kitchenette with a microwave, refrigerator, and hot and cold water dispenser. There 2 bathrooms with a hair dryer. The air-conditioned unit at the property features a bidet and water heater. This apartment is allergy-free. A minimarket, vending machine and self service laundry is available at the apartment .

For guest with children, the apartment provides kids pool, and indoor and outdoor playground. Barbecue facilities and Tennis Court are included at the apartment complex, and guest can also relax in the garden or go on a picnic in the picnic area.

Bangi Wonderland is 5km from Palmyra Residence Whole Condo, While Bandar Baru Bangi is 15km away. The nearest airport is Kuala Lumpur International Airport, 30km from the accommodation.', 'Kajang', 'Malaysia', 'RESIDENSI PALMERA, LAMAN PUTERI 3, BANDAR PUTERI BANGI BLOCK B-30-3A, 43000 Kajang, Malaysia', 2.8774892295411, 101.79408609867, '["Air Conditioner (Cooling)", "Hair Dryer", "Elevator in Building", "Parking on Premises", "Gym", "Pool", "TV", "Wheelchair Accessible", "Free Wi-Fi"]', NULL, '100% FOR ONE DAY BEFORE ARRIVALS', '2024-03-14 12:31:19', 1);
