INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Workspace Rentals in Cebu Mandaue', 'zero-ten-park-mandaue', 'Located inside JDN Building 4 in Banilad, The Company Mandaue sits at the sweet spot between creative calm and city access. It’s perfect for professionals who want to work without the chaos of downtown. This space feels personal—warm lighting, wooden furniture, curated playlists, and walls lined with Cebuano art make it easy to settle in and get to work. Whether you’re here for a few hours or building something long-term, people work, connect, pause, and grow here. Like our IT Park location, we showcase works by local artists like Pinspired, Beth Dayto, and Zar On Canvas, all available for purchase. It’s co-working with culture, set in a neighborhood built for balance and quiet momentum.', 'Cebu', 'philippines', 'Ground Floor, Building 4, JDN Square, P.Remedio St, Mandaue City, 6014, Cebu, Philippines', 10.3432772, 123.9205385, '["Air Conditioner (Cooling)", "Projector(s)", "Scanner / Printer", "TV", "Free Wi-Fi"]', 'Shared Room', 'The following cancellation policy is set forth on our website and applies at the time of reservation.\nCancellation on the day of use will incur a cancellation fee of 100% of the usage fee.\nCancellation up to 24 hours prior to the start of use will not incur a cancellation fee.', '2026-02-09 18:50:20', 1);
