INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Workspace Rentals in Cebu IT Park', 'zero-ten-park-itpark', 'The Company Cebu – IT Park is located inside Mabuhay Tower, a PEZA-accredited, modern office building in the heart of Cebu’s premier business district. The tower features high-speed elevators, 24/7 security, reliable backup power, and professional-grade facilities — all designed to support businesses of every size. Within this smartly designed space, The Company fosters a collaborative and inclusive community of freelancers, startups, virtual assistants, and remote tech teams. Members enjoy flexible workspaces, creative lounges, curated events, and access to a growing network of professionals who believe in doing meaningful work. The surrounding neighborhood pulses with energy — from coffee shops and cowork-friendly cafes to large-scale BPOs and innovation hubs — giving our members both the convenience of location and the spark of connection.', 'Cebu', 'philippines', '6th Floor, Mabuhay Tower, IT Park Corner Jose maria del Mar St, Abad St, Cebu City, Cebu, Philippines', 10.3284087, 123.9064042, '["Free Wi-Fi"]', 'Shared Room', 'The following cancellation policy is set forth on our website and applies at the time of reservation.\r\nCancellation on the day of use will incur a cancellation fee of 100% of the usage fee.\r\nCancellation up to 24 hours prior to the start of use will not incur a cancellation fee.', '2026-02-09 19:01:58', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Workspace Rentals in Cebu IT Park', 'zero-ten-park-itpark', 'The Company Cebu – IT Park is located inside Mabuhay Tower, a PEZA-accredited, modern office building in the heart of Cebu’s premier business district. The tower features high-speed elevators, 24/7 security, reliable backup power, and professional-grade facilities — all designed to support businesses of every size. Within this smartly designed space, The Company fosters a collaborative and inclusive community of freelancers, startups, virtual assistants, and remote tech teams. Members enjoy flexible workspaces, creative lounges, curated events, and access to a growing network of professionals who believe in doing meaningful work. The surrounding neighborhood pulses with energy — from coffee shops and cowork-friendly cafes to large-scale BPOs and innovation hubs — giving our members both the convenience of location and the spark of connection.', 'Cebu', 'philippines', '6th Floor, Mabuhay Tower, IT Park Corner Jose maria del Mar St, Abad St, Cebu City, Cebu, Philippines', 10.3284087, 123.9064042, '[]', NULL, 'The following cancellation policy is set forth on our website and applies at the time of reservation.\r\nCancellation on the day of use will incur a cancellation fee of 100% of the usage fee.\r\nCancellation up to 24 hours prior to the start of use will not incur a cancellation fee.', '2026-02-09 19:01:58', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Sunset Beach Club Experience', 'sunset-beach-club-experience', 'Your afternoon begins with a seamless, air-conditioned transfer from your hotel or port. We’ll whisk you away to one of the region’s premier Sunset Beach Clubs, handpicked for its stunning architecture, chilled atmosphere, and unobstructed ocean views.

Once there, the time is yours. Sink into a plush daybed, take a dip in the crystal-clear infinity pool, or stroll along the white sands. As the afternoon matures, the DJ’s tempo drops, the cocktails flow, and the sky begins its nightly transformation into a canvas of fiery oranges and deep purples.

🕒 Itinerary
15:30 – 16:00 | Afternoon Pickup: Comfortable door-to-door service from your hotel or cruise terminal.

16:30 | Arrival at Paradise: Check-in at our partner beach club.

16:30 – 18:00 | Leisure Time: Swim, lounge, or explore the club’s amenities.

18:00 – 18:45 | The Sunset Ritual: Experience the breathtaking transition from day to dusk over the ocean.

19:30 | Return Transfer: We’ll bring you back to your hotel in time for a late dinner, refreshed and \"sun-kissed.\"

Duration: Approximately 5 hours.

Inclusions: Round-trip private transfers and access to pool/changing facilities.

Exclusions: Food, beverages, and beach club entrance fee, daybed rental fees (unless pre-booked).

What to Bring: Swimwear, sunscreen, a camera, and your favorite sunglasses.

Important note:
Last time booking is at 9:00am', 'Bali', 'indonesia', 'Jl. Padma No.2, Legian, Kec. Kuta', -8.706871, 115.1670537, '[]', NULL, 'Cancellation on the day of use will incur a cancellation fee of 100% of the usage fee. Cancellation up to 24 hours prior to the start of use will not incur a cancellation fee and fully refunded', '2026-02-18 14:10:05', 1);
