INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Tegenungan Waterfall &amp; Coffee Plantation Experience', 'tegenungan-waterfall-coffee-plantation-experience', 'DESCRIPTION
Experience the raw power of Bali’s nature and the rich aromas of its highlands in this efficient 4 to 5-hour escape. This tour takes you to Tegenungan, one of the island''s most iconic and accessible waterfalls, located in a lush jungle valley. Following your nature trek, you will dive into Bali’s agricultural heritage at a traditional coffee plantation. It is the perfect blend of scenic photography, light adventure, and a sensory journey through the world of Balinese coffee and herbal teas.

HIGHLIGHTS
Majestic Tegenungan Waterfall: Witness the impressive 15-meter drop and the tropical greenery of the Petanu River.
Iconic Photo Spots: Capture stunning shots from the high-level viewpoints or right at the base of the falls.
Bean-to-Cup Experience: Discover the traditional methods of Balinese coffee roasting and the famous Luwak coffee process.
Guided Tasting Session: Enjoy a complimentary flight of local coffees and exotic herbal teas overlooking the plantation.
Flexible Half-Day Pace: A perfect morning or afternoon excursion that leaves the rest of your day free.

INCLUDE
Private Hotel Pickup &amp; Drop-off: Door-to-door service in a private, air-conditioned vehicle.
Entrance Tickets: Tegenungan Waterfall 
Professional Private Driver: An English-speaking driver who manages all navigation and parking.
Coffee Plantation Visit: Guided tour of the gardens and production area.
Tasting Flight: A variety of local coffee and tea samples.
Refreshments: Bottled mineral water in the vehicle.

NOT INCLUDE
Personal Expenses: Purchases at the coffee plantation shop or lunch.
Gratuities: Tips for the driver 

NOTE
Footwear: Expect some stairs at the waterfall; comfortable walking shoes or sturdy sandals are recommended.
Best Time to Visit: Early morning (08:30 AM) is best to avoid the midday heat and larger crowds.
Swim Ready: If you wish to get close to the water, bring a towel and a change of clothes (changing rooms are available on-site).
Accessibility: The plantation is generally easy to walk, while the waterfall involves a descent and ascent of approximately 150 stairs.', 'Bali', 'indonesia', 'Kemenuh', -8.5655356, 115.2861105, '[]', 'Hotel', 'Cancellation on the day of use will incur a cancellation fee of 100% of the usage fee. Cancellation up to 24 hours prior to the start of use will not incur a cancellation fee and fully refunded', '2026-02-25 10:27:54', 1);
