INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Munduk: Twin Lake Jungle Hike, Traditional Canoe &amp; Waterfall', 'munduk-twin-lake-jungle-hike-traditional-canoe-waterfall', 'DESCRIPTION
Escape the bustling tourist hubs and journey into the mist-shrouded highlands of North Bali. This immersive experience centers around the sacred Twin Lakes—Buyan and Tamblingan. You will trek through ancient rainforests where giant ferns and centuries-old banyan trees dominate the landscape. The journey includes a serene crossing of Lake Tamblingan in a traditional dugout canoe to reach hidden, moss-covered temples that few travelers ever see. Finish your adventure with a refreshing visit to the stunning Banyumala Twin Waterfalls, tucked deep within a lush jungle ravine.

HIGHLIGHTS
Immersive Rainforest Trek: Hike through the diverse flora and fauna of the North Bali highlands with an expert guide.
Traditional Canoe Crossing: Experience a peaceful 30-minute glide across Lake Tamblingan in a classic hand-carved wooden boat.
Hidden Lake Temples: Discover the ancient Pura Ulun Danu Tamblingan, a spiritual gem located right on the water’s edge.
Twin Lake Viewpoint: Stop at the iconic Wanagiri ridge for panoramic views of the caldera lakes below.
Banyumala Waterfalls: Swim and relax at one of Bali’s most beautiful and naturally preserved twin waterfalls.

INCLUDE

Professional Trekking Guide: A local expert to lead the hike and share knowledge of forest healing plants.
Traditional Canoe Rental: Private boat crossing on Lake Tamblingan.
Entrance Tickets: All fees for the jungle trek, lake area, and waterfalls.
Refreshments: Bottled mineral water and a traditional Balinese sticky rice snack.

NOT INCLUDE
Hotel Pickup &amp; Drop-off
Lunch: Local restaurant stops are available but the cost of the meal is not included.
Personal Expenses: Souvenirs or additional snacks along the way.
Gratuities: Tips for your guide and driver.

NOTE
Start Early: We highly recommend a 07:00 AM or 07:15 AM pickup to beat the afternoon mountain mist and occasional rain.
Proper Gear: Please wear comfortable hiking shoes or sneakers with good grip. Bring swimwear and a towel if you wish to swim.
Weather: The Munduk area is significantly cooler than the coast; bringing a light jacket or long-sleeved shirt is advised.
Fitness Level: This hike involves moderate physical activity including some stairs and uneven forest terrain.', 'Bali', 'indonesia', 'wanagiri bali adventure', -8.2463591, 115.1008117, '[]', 'Hotel', 'Cancellation on the day of use will incur a cancellation fee of 100% of the usage fee. Cancellation up to 24 hours prior to the start of use will not incur a cancellation fee and fully refunded', '2026-02-25 14:04:13', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Munduk: Twin Lake Jungle Hike, Traditional Canoe &amp; Waterfall', 'munduk-twin-lake-jungle-hike-traditional-canoe-waterfall', 'DESCRIPTION
Escape the bustling tourist hubs and journey into the mist-shrouded highlands of North Bali. This immersive experience centers around the sacred Twin Lakes—Buyan and Tamblingan. You will trek through ancient rainforests where giant ferns and centuries-old banyan trees dominate the landscape. The journey includes a serene crossing of Lake Tamblingan in a traditional dugout canoe to reach hidden, moss-covered temples that few travelers ever see. Finish your adventure with a refreshing visit to the stunning Banyumala Twin Waterfalls, tucked deep within a lush jungle ravine.

HIGHLIGHTS
Immersive Rainforest Trek: Hike through the diverse flora and fauna of the North Bali highlands with an expert guide.
Traditional Canoe Crossing: Experience a peaceful 30-minute glide across Lake Tamblingan in a classic hand-carved wooden boat.
Hidden Lake Temples: Discover the ancient Pura Ulun Danu Tamblingan, a spiritual gem located right on the water’s edge.
Twin Lake Viewpoint: Stop at the iconic Wanagiri ridge for panoramic views of the caldera lakes below.
Banyumala Waterfalls: Swim and relax at one of Bali’s most beautiful and naturally preserved twin waterfalls.

INCLUDE

Professional Trekking Guide: A local expert to lead the hike and share knowledge of forest healing plants.
Traditional Canoe Rental: Private boat crossing on Lake Tamblingan.
Entrance Tickets: All fees for the jungle trek, lake area, and waterfalls.
Refreshments: Bottled mineral water and a traditional Balinese sticky rice snack.

NOT INCLUDE
Hotel Pickup &amp; Drop-off
Lunch: Local restaurant stops are available but the cost of the meal is not included.
Personal Expenses: Souvenirs or additional snacks along the way.
Gratuities: Tips for your guide and driver.

NOTE
Start Early: We highly recommend a 07:00 AM or 07:15 AM pickup to beat the afternoon mountain mist and occasional rain.
Proper Gear: Please wear comfortable hiking shoes or sneakers with good grip. Bring swimwear and a towel if you wish to swim.
Weather: The Munduk area is significantly cooler than the coast; bringing a light jacket or long-sleeved shirt is advised.
Fitness Level: This hike involves moderate physical activity including some stairs and uneven forest terrain.', 'Bali', 'indonesia', 'wanagiri bali adventure', -8.2463591, 115.1008117, '[]', NULL, 'Cancellation on the day of use will incur a cancellation fee of 100% of the usage fee. Cancellation up to 24 hours prior to the start of use will not incur a cancellation fee and fully refunded', '2026-02-25 14:04:13', 1);
INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Ubud: Sacred Monkey Forest, Rice Terrace &amp; Waterfall Private Tour', 'ubud-sacred-monkey-forest-rice-terrace-waterfall-private-tour', 'DESCRIPTION
Experience the cultural heart of Bali on this private full-day journey through Ubud’s most legendary sights. Your adventure begins in the shade of ancient banyan trees at the Sacred Monkey Forest, followed by the breathtaking emerald vistas of the Tegalalang Rice Terraces. You will delve into Balinese spirituality at the Tirta Empul holy water temple and explore the island''s flavors at a local coffee plantation. The day concludes at the hidden Tibumana Waterfall, a serene oasis perfect for a refreshing swim. This tour is the ultimate introduction to the nature, culture, and traditions that make Ubud world-famous.

HIGHLIGHTS

* Sacred Monkey Forest Sanctuary: Observe long-tailed macaques in their natural habitat amongst ancient jungle temples.
* Tegalalang Rice Terrace: Walk through the iconic stepped landscapes and learn about the traditional "Subak" irrigation system.
* Tirta Empul Holy Water Temple: Witness the sacred purification rituals at one of Bali’s most important Hindu water temples.
* Plantation Coffee Tasting: Sample authentic Balinese coffee and exotic herbal teas with views of the lush countryside.
* Tibumana Waterfall: Escape to a peaceful, curtain-style waterfall tucked away in a verdant jungle ravine.

INCLUDE

* Private Hotel Pickup &amp; Drop-off: Air-conditioned transport from all major South and Central Bali areas.
* Professional Driver-Guide: An English-speaking expert to provide cultural insights and assist with photography.
* Temple Sarong: Traditional waistcloth provided for respectful entry into Tirta Empul.
* Bottled Water: Stay hydrated with complimentary mineral water throughout the trip.
* All Parking Fees: Stress-free logistics with all vehicle-related costs covered.

NOT INCLUDE

* Entrance Tickets: Admission fees for the Monkey Forest ( IDR 120.000), Rice Terrace ( IDR 50.000), Temple (IDR 75.000), and Waterfall (50.000) per person.
* Lunch: We will stop at a recommended local restaurant, but the cost of the meal is not included.
* Personal Expenses: Souvenirs, Luwak coffee upgrades, or optional activities (like the Jungle Swing).
* Gratuities: Tips for your driver-guide are at your discretion.

NOTE

* Recommended Start Time: 08:00 AM or 08:30 AM to maximize your time and avoid peak afternoon crowds.
* Dress Code: Shoulders must be covered for temple entry; a sarong will be provided for your waist.
* Footwear: Comfortable walking shoes or sturdy sandals are essential for the rice terraces and waterfall path.
* Swim Ready: Bring a towel and a change of clothes if you plan to swim at the waterfall.
* Monkey Safety: Please secure all loose items (sunglasses, hats, jewelry) before entering the Monkey Forest.', 'Bali', 'indonesia', 'Ubud', -8.5068536, 115.2624778, '[]', 'Hotel', 'Cancellation on the day of use will incur a cancellation fee of 100% of the usage fee. Cancellation up to 24 hours prior to the start of use will not incur a cancellation fee and fully refunded', '2026-02-25 14:34:49', 1);
