INSERT OR IGNORE INTO hotels (name, slug, description, city, country, address, latitude, longitude, amenities, property_type, cancellation_policy, created_at, is_active) VALUES ('Bali UNESCO Wonders: Ulun Danu, Jatiluwih &amp; Tanah Lot Sunset', 'bali-unesco-wonders-ulun-danu-jatiluwih-tanah-lot-sunset', 'DESCRIPTION
Embark on a private journey through the landscapes that earned Bali its UNESCO World Heritage status. This tour takes you from the misty highlands of Bedugul to the dramatic southern coastline. You will visit the "Floating Temple" of Ulun Danu Beratan, nestled on a serene lake, before wandering through the endless emerald waves of the Jatiluwih Rice Terraces. The day concludes with a spectacular sunset at Tanah Lot, an ancient sea temple perched on a rocky offshore formation. This is a comprehensive exploration of Bali’s iconic architecture and its world-famous agricultural heritage.

HIGHLIGHTS

* Ulun Danu Beratan Temple: Marvel at the iconic 11-story "floating" pagoda on the shores of Lake Beratan.
* Jatiluwih Rice Terraces (UNESCO): Explore the largest and most scenic rice terraces in Bali, showcasing the ancient Subak irrigation system.
* Tanah Lot Sea Temple: Witness one of Bali’s most dramatic sights as the sun sets behind the 16th-century temple on the ocean.
* Scenic Mountain Drive: Enjoy the cooler temperatures and lush vegetable gardens of the Bedugul highlands.
* Cultural Heritage: Learn the history of the "Water Temples" and their vital role in Balinese life and religion.

INCLUDE

* Private Hotel Pickup &amp; Drop-off: Door-to-door transport in a comfortable air-conditioned vehicle.
* Professional Driver-Guide: An English-speaking expert to assist with history, culture, and photos.
* All Parking Fees: No hidden costs for vehicle logistics throughout the day.
* Bottled Water: Mineral water provided to keep you refreshed.
* Temple Sarong: Use of a traditional sarong for respectful entry into temple grounds.

NOT INCLUDE

* Entrance Tickets: Admission fees for Ulun Danu (IDR 75.000), Jatiluwih (IDR 75.000), and Tanah Lot (IDR 75.000).
* Lunch: We will stop at a panoramic restaurant in Jatiluwih, but meals are not included.
* Personal Expenses: Souvenirs or additional snacks.
* Gratuities: Tips for the driver-guide are at your discretion.

NOTE

* Recommended Start Time: **08:30 AM** is ideal to ensure you have enough time to enjoy the highlands before reaching Tanah Lot for sunset.
* Temperature Shift: The Bedugul mountains can be quite cool and misty; bringing a light jacket or sweater is recommended.
* Footwear: Comfortable walking shoes are a must for exploring the paths at the Jatiluwih Rice Terraces.
* Respectful Attire: Please wear clothing that covers your shoulders for temple visits.
* Sunset Timing: Tanah Lot is very popular at sunset; your driver will ensure you arrive early to secure a prime viewing spot.', 'Bali', 'indonesia', 'Ulundanu Beratan', -8.2751807, 115.1668234, '[]', 'Hotel', 'Cancellation on the day of use will incur a cancellation fee of 100% of the usage fee. Cancellation up to 24 hours prior to the start of use will not incur a cancellation fee and fully refunded', '2026-02-25 15:20:16', 1);
